function largestMagicSquare(grid) {
    const m = grid.length, n = grid[0].length;
    const row = Array.from({length: m}, () => Array(n + 1).fill(0));
    const col = Array.from({length: m + 1}, () => Array(n).fill(0));

    for (let i = 0; i < m; ++i) {
        for (let j = 0; j < n; ++j) {
            row[i][j + 1] = row[i][j] + grid[i][j];
            col[i + 1][j] = col[i][j] + grid[i][j];
        }
    }

    for (let k = Math.min(m, n); k > 1; --k) {
        for (let i = 0; i + k - 1 < m; ++i) {
            for (let j = 0; j + k - 1 < n; ++j) {
                const sum = row[i][j + k] - row[i][j];
                let ok = true;
                for (let t = 1; t < k; ++t) {
                    if (row[i + t][j + k] - row[i + t][j] !== sum || col[i + k][j + t] - col[i][j + t] !== sum) {
                        ok = false;
                        break;
                    }
                }
                if (!ok) continue;

                let diag1 = 0, diag2 = 0;
                for (let t = 0; t < k; ++t) {
                    diag1 += grid[i + t][j + t];
                    diag2 += grid[i + t][j + k - 1 - t];
                }
                if (diag1 === sum && diag2 === sum) return k;
            }
        }
    }

    return 1;
}
```


    1. First, compute the row and column cumulative sums in `row` and `col` matrices.
2. Iterate `k` from the minimum of `m` and `n` down to 2, which represents the size of the potential magic square.
3. For each `k`, iterate through all possible top-left corners `(i, j)` of the magic square.
4. Check if all row and column sums match. If any do not, skip this position.
5. Calculate both diagonal sums of the magic square. If both diagonal sums match the row and column sums, return `k` as the largest magic square size.
6. If no magic square with size > 1 is found, return 1.

